UCLASS()
class AMyGameMode : public AGameModeBase {
    GENERATED_BODY()
public:
    AMyGameMode() {
        DefaultPawnClass = AMyCharacter::StaticClass();
        PlayerControllerClass = AMyPlayerController::StaticClass();
        GameStateClass = AMyGameState::StaticClass();
        PlayerStateClass = AMyPlayerState::StaticClass();
    }

    virtual void PostLogin(APlayerController* NewPlayer) override {
        Super::PostLogin(NewPlayer);
        // Player just joined - set up initial state
    }
};

UCLASS()
class AMyGameState : public AGameStateBase {
    GENERATED_BODY()
public:
    UPROPERTY(Replicated)
    int32 TeamAScore;

    UPROPERTY(Replicated)
    int32 TeamBScore;

    UPROPERTY(Replicated)
    float MatchTimeRemaining;
};

UCLASS()
class AMyPlayerState : public APlayerState {
    GENERATED_BODY()
public:
    UPROPERTY(Replicated)
    int32 Kills;

    UPROPERTY(Replicated)
    int32 Deaths;

    UPROPERTY(Replicated)
    ETeam CurrentTeam;
};

UCLASS()
class AMyCharacter : public ACharacter {
    GENERATED_BODY()
public:
    AMyCharacter() {
        // CharacterMovement is auto-created
        GetCharacterMovement()->MaxWalkSpeed = 600.f;
        GetCharacterMovement()->JumpZVelocity = 420.f;
    }

    virtual void SetupPlayerInputComponent(UInputComponent* PIC) override {
        Super::SetupPlayerInputComponent(PIC);
        // Bind input here — only called for locally controlled pawn
    }
};
